sql:
SELECT energy_production.mtu, energy_production.biomass_actual
FROM energy_production
INNER JOIN areas ON energy_production.area = areas.area_name;

SELECT areas.area_name, energy_production_summary.total_production_mw
FROM energy_production_summary
INNER JOIN areas ON energy_production_summary.area_id = areas.area_id;

SELECT area, fossil_brown_coal
FROM energy_production
ORDER BY fossil_brown_coal DESC;

SELECT eps.total_production_mw, a.country
FROM energy_production_summary eps
INNER JOIN areas a ON eps.area_id = a.area_id;

SELECT energy_type_name 
FROM energy_types 
WHERE energy_type_id = 1;

SELECT log_id, QUOTE(event_type) 
FROM production_logs 
WHERE event_type = 'data collection';

SELECT total_renewable_mw, period_start, period_end
FROM energy_production_summary
WHERE area_id = 1;

SELECT description, accuracy
FROM predictive_models
WHERE model_type = 'regression' AND accuracy > 0.8;

SELECT MAX(solar_actual) AS max_solar_production
FROM energy_production
WHERE area = '1';
